def test_aggregate_transform():
    t = AggregateTransform('dept', 'sum')
    data = [
        {'dept': 'eng', 'salary': 100},
        {'dept': 'eng', 'salary': 120},
        {'dept': 'sales', 'salary': 80}
    ]
    result = t.apply(data)
    result_dict = {r['dept']: r for r in result}
    assert result_dict['eng']['salary'] == 220
    assert result_dict['sales']['salary'] == 80
